class Solution {
public:
    int maximumLength(string s) {
        int n = s.size();
        int res = -1;
        for (char c = 'a'; c <= 'z'; ++c) {
            int cnt = 0, max_len = 0, curr_len = 0;
            for (int i = 0; i < n; ++i) {
                if (s[i] == c) {
                    curr_len++;
                } else {
                    if (curr_len >= 1) max_len = max(max_len, curr_len);
                    if (curr_len >= 2) cnt++;
                    if (curr_len >= 3) cnt++;
                    curr_len = 0;
                }
            }
            if (curr_len >= 1) max_len = max(max_len, curr_len);
            if (curr_len >= 2) cnt++;
            if (curr_len >= 3) cnt++;
            if (cnt >= 3) res = max(res, max_len);
        }
        return res;
    }
};
